1	/**
2	 * nsg plugin-* — manage guild plugins.
3	 *
4	 * Framework commands for plugin lifecycle. Available via CLI only (not MCP).
5	 *
6	 * Plugin install/remove are pure npm + guild.json operations. No tool
7	 * discovery at install time — tools are resolved at runtime by the
8	 * Instrumentarium via its permission-based model.
9	 */
10	
11	import fs from 'node:fs';
12	import path from 'node:path';
13	import { execFileSync } from 'node:child_process';
14	import { tool } from '@shardworks/tools-apparatus';
15	import {
16	  guild,
17	  readGuildConfig,
18	  writeGuildConfig,
19	  derivePluginId,
20	  readGuildPackageJson,
21	  resolvePackageNameForPluginId,
22	} from '@shardworks/nexus-core';
23	import { z } from 'zod';
24	
25	// ── Helpers ────────────────────────────────────────────────────────────
26	
27	function npm(args: string[], cwd: string): string {
28	  return execFileSync('npm', args, { cwd, stdio: 'pipe', encoding: 'utf-8' });
29	}
30	
31	function pnpm(args: string[], cwd: string): string {
32	  return execFileSync('pnpm', args, { cwd, stdio: 'pipe', encoding: 'utf-8' });
33	}
34	
35	/**
36	 * Detect the package manager used by the guild.
37	 *
38	 * Checks for lockfiles in order of specificity. Falls back to 'npm'
39	 * when no lockfile is present (e.g. fresh guilds before first install).
40	 */
41	export function detectPackageManager(guildRoot: string): 'npm' | 'pnpm' {
42	  if (fs.existsSync(path.join(guildRoot, 'pnpm-lock.yaml'))) return 'pnpm';
43	  return 'npm';
44	}
45	
46	/**
47	 * Parse a source specifier to extract the npm package name.
48	 * e.g. "@shardworks/nexus-stdlib@1.0" → "@shardworks/nexus-stdlib"
49	 *      "nexus-stdlib" → "nexus-stdlib"
50	 *
51	 * Returns null for git URLs — the package name must be read from
52	 * the guild's package.json after npm install.
53	 *
54	 * Known limitations: does not handle npm: alias specifiers, tarball URLs,
55	 * or workspace: protocol. These are uncommon for plugin install and can
56	 * be added if needed.
57	 */
58	function parsePackageName(source: string): string | null {
59	  if (source.startsWith('git+') || source.startsWith('git://') || source.endsWith('.git')) {
60	    return null;
61	  }
62	  if (source.startsWith('@')) {
63	    const lastAt = source.lastIndexOf('@');
64	    if (lastAt > 0) return source.substring(0, lastAt);
65	    return source;
66	  }
67	  if (source.includes('@')) {
68	    return source.split('@')[0]!;
69	  }
70	  return source;
71	}
72	
73	/**
74	 * Find the most recently added dependency in the guild's package.json.
75	 * Used after `npm install <git-url>` where we can't parse the name from the source.
76	 *
77	 * Relies on Object.keys() returning insertion-ordered string keys (guaranteed
78	 * by the ES2015 spec for non-integer keys, and by V8/Node). A diff-based
79	 * approach (snapshot deps before install, compare after) would be more robust
80	 * but overkill for this edge case.
81	 */
82	function detectInstalledPackage(guildRoot: string): string {
83	  const pkgPath = path.join(guildRoot, 'package.json');
84	  const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf-8'));
85	  const deps = pkg.dependencies as Record<string, string> | undefined ?? {};
86	  const names = Object.keys(deps);
87	  const last = names[names.length - 1];
88	  if (!last) throw new Error('Could not determine package name after npm install.');
89	  return last;
90	}
91	
92	// ── Commands ───────────────────────────────────────────────────────────
93	
94	export const pluginList = tool({
95	  name: 'plugin-list',
96	  description: 'List installed plugins',
97	  callableBy: ['patron'],
98	  params: {
99	    json: z.boolean().optional().describe('Output as JSON'),
100	  },
101	  handler: async (params) => {
102	    const { home } = guild();
103	    const config = readGuildConfig(home);
104	    const pluginIds = config.plugins;
105	
106	    if (pluginIds.length === 0) {
107	      if (params.json) return [];
108	      return 'No plugins installed.';
109	    }
110	
111	    if (params.json) {
112	      return [...pluginIds].sort().map((id) => ({ id }));
113	    }
114	    return [...pluginIds].sort().join('\n');
115	  },
116	});
117	
118	export const pluginInstall = tool({
119	  name: 'plugin-install',
120	  description: 'Install a plugin into the guild',
121	  callableBy: ['patron'],
122	  params: {
123	    source: z.string().describe('Package name, git URL, or local folder path'),
124	    type: z.enum(['registry', 'link']).optional().describe('Install type: "registry" (npm install) or "link" (local folder). Auto-detected when source is a folder path.'),
125	  },
126	  handler: async (params) => {
127	    const { home } = guild();
128	    const { source } = params;
129	
130	    // Auto-detect link mode when source looks like a filesystem path
131	    const sourceDir = path.resolve(source);
132	    const looksLikePath = source.startsWith('.') || source.startsWith('/');
133	    const isDirectory = looksLikePath && fs.existsSync(sourceDir) && fs.statSync(sourceDir).isDirectory();
134	    const installType = params.type ?? (isDirectory ? 'link' : 'registry');
135	
136	    // 1. Install the npm package into the guild
137	    let packageName: string;
138	
139	    if (installType === 'link') {
140	      const sourceDir = path.resolve(source);
141	      if (!fs.existsSync(path.join(sourceDir, 'package.json'))) {
142	        throw new Error(`No package.json found in ${sourceDir}. --link requires a directory with a package.json.`);
143	      }
144	      const pkgJson = JSON.parse(fs.readFileSync(path.join(sourceDir, 'package.json'), 'utf-8')) as Record<string, unknown>;
145	      packageName = pkgJson.name as string;
146	      const pm = detectPackageManager(home);
147	      if (pm === 'pnpm') {
148	        pnpm(['add', `link:${sourceDir}`], home);
149	      } else {
150	        npm(['install', '--save', `file:${sourceDir}`], home);
151	      }
152	    } else {
153	      npm(['install', '--save', source], home);
154	      packageName = parsePackageName(source) ?? detectInstalledPackage(home);
155	
156	      const { pkgJson } = readGuildPackageJson(home, packageName);
157	      if (!pkgJson) {
158	        throw new Error(`Package "${packageName}" not found in node_modules after install.`);
159	      }
160	    }
161	
162	    const pluginId = derivePluginId(packageName);
163	
164	    // 2. Update guild.json — add to plugins list
165	    const config = readGuildConfig(home);
166	
167	    if (!config.plugins.includes(pluginId)) {
168	      config.plugins.push(pluginId);
169	    }
170	
171	    writeGuildConfig(home, config);
172	
173	    return `Installed plugin: ${pluginId} (${packageName})`;
174	  },
175	});
176	
177	export const pluginRemove = tool({
178	  name: 'plugin-remove',
179	  description: 'Remove a plugin from the guild',
180	  callableBy: ['patron'],
181	  params: {
182	    name: z.string().describe('Plugin id or package name to remove'),
183	  },
184	  handler: async (params) => {
185	    const { home } = guild();
186	    const config = readGuildConfig(home);
187	    const targetId = params.name.startsWith('@') ? derivePluginId(params.name) : params.name;
188	
189	    if (!config.plugins.includes(targetId)) {
190	      throw new Error(`Plugin "${targetId}" is not installed.`);
191	    }
192	
193	    config.plugins = config.plugins.filter((id) => id !== targetId);
194	    writeGuildConfig(home, config);
195	
196	    const packageName = resolvePackageNameForPluginId(home, targetId);
197	    if (packageName) {
198	      try {
199	        const pm = detectPackageManager(home);
200	        if (pm === 'pnpm') {
201	          pnpm(['remove', packageName], home);
202	        } else {
203	          npm(['uninstall', packageName], home);
204	        }
205	      } catch {
206	        // Don't fail if uninstall fails — guild.json is already updated
207	      }
208	    }
209	
210	    return `Removed plugin: ${targetId}`;
211	  },
212	});
213	
214	export const pluginUpgrade = tool({
215	  name: 'plugin-upgrade',
216	  description: 'Upgrade a plugin to a newer version',
217	  callableBy: ['patron'],
218	  params: {
219	    name: z.string().describe('Plugin id or package name to upgrade'),
220	    version: z.string().optional().describe('Target version (default: latest)'),
221	  },
222	  handler: async () => {
223	    return 'Not yet implemented.';
224	  },
225	});
226

