87	/**
88	 * An engine design — the unit of work the Fabricator catalogues and the
89	 * Spider executes. Kit authors import this type from @shardworks/fabricator-apparatus.
90	 */
91	export interface EngineDesign {
92	  /** Unique identifier for this engine design (e.g. 'draft', 'implement', 'review'). */
93	  id: string;
94	
95	  /**
96	   * Execute this engine.
97	   *
98	   * @param givens   — the engine's declared inputs, assembled by the Spider.
99	   * @param context  — minimal execution context: engine id and upstream yields.
100	   */
101	  run(givens: Record<string, unknown>, context: EngineRunContext): Promise<EngineRunResult>;
102	
103	  /**
104	   * Assemble yields from a completed session.
105	   *
106	   * Called by the Spider's collect step when a quick engine's session
107	   * reaches a terminal state. The engine looks up whatever it needs
108	   * via guild() — same dependency pattern as run().
109	   *
110	   * @param sessionId — the session to collect yields from (primary input).
111	   * @param givens    — same givens that were passed to run().
112	   * @param context   — same execution context that was passed to run().
113	   *
114	   * If not defined, the Spider uses a generic default:
115	   *   { sessionId, sessionStatus, output? }
116	   *
117	   * Only relevant for quick engines (those that return { status: 'launched' }).
118	   * Clockwork engines return yields directly from run().
119	   */
120	  collect?(sessionId: string, givens: Record<string, unknown>, context: EngineRunContext): Promise<unknown>;
121	
122	  /**
123	   * Opt-in retry policy. When absent, the engine has no retry budget
124	   * (effectively `maxAttempts: 0`). Validated at registration — a
125	   * malformed block throws at startup.
126	   */
127	  retry?: EngineRetryConfig;
128	}
129	
130	// ── Retry config defaults and validation ──────────────────────────────
131	
132	/**
133	 * Default back-off values applied when a retry-enabled engine design
134	 * omits explicit back-off. Chosen short — retry is a rig-local mechanism,
135	 * not a long-term scheduler. 30s initial, 10m cap, 2x growth.
136	 */
137	export const DEFAULT_ENGINE_RETRY_BACKOFF: EngineRetryBackoffConfig = Object.freeze({
138	  initialMs: 30_000,
139	  maxMs: 600_000,
140	  factor: 2,
141	}) as EngineRetryBackoffConfig;
142	
143	/**
144	 * Validate a retry config fail-loud at registration time. Fills in
145	 * default back-off values for fields the caller omitted. Throws a
146	 * descriptive error if any supplied value is malformed.
147	 *
148	 * Checks:
149	 *  - `maxAttempts` must be a non-negative integer.
150	 *  - `backoff.initialMs` must be a positive integer.
151	 *  - `backoff.maxMs` must be a positive integer and >= `initialMs`.
152	 *  - `backoff.factor` must be a finite number > 1.
153	 *
154	 * Returns the resolved config (all back-off fields populated) when the
155	 * input passes.
156	 */
157	export function validateEngineRetryConfig(
158	  designId: string,
159	  raw: EngineRetryConfig,
160	): EngineRetryConfig & { backoff: EngineRetryBackoffConfig } {
161	  if (typeof raw !== 'object' || raw === null) {
162	    throw new Error(
163	      `[fabricator] engine "${designId}": retry config must be an object; received ${typeof raw}`,
164	    );
165	  }
166	  if (!Number.isInteger(raw.maxAttempts) || raw.maxAttempts < 0) {
167	    throw new Error(
168	      `[fabricator] engine "${designId}": retry.maxAttempts must be a non-negative integer; received ${String(raw.maxAttempts)}`,
169	    );
170	  }
171	
172	  const resolved: EngineRetryBackoffConfig = { ...DEFAULT_ENGINE_RETRY_BACKOFF };
173	  const backoff = raw.backoff ?? {};
174	  if (typeof backoff !== 'object' || backoff === null) {
175	    throw new Error(
176	      `[fabricator] engine "${designId}": retry.backoff must be an object; received ${typeof backoff}`,
177	    );
178	  }
179	  if (backoff.initialMs !== undefined) {
180	    if (!Number.isInteger(backoff.initialMs) || backoff.initialMs <= 0) {
181	      throw new Error(
182	        `[fabricator] engine "${designId}": retry.backoff.initialMs must be a positive integer; received ${String(backoff.initialMs)}`,
183	      );
184	    }
185	    resolved.initialMs = backoff.initialMs;
186	  }
187	  if (backoff.maxMs !== undefined) {
188	    if (!Number.isInteger(backoff.maxMs) || backoff.maxMs <= 0) {
189	      throw new Error(
190	        `[fabricator] engine "${designId}": retry.backoff.maxMs must be a positive integer; received ${String(backoff.maxMs)}`,
191	      );
192	    }
193	    resolved.maxMs = backoff.maxMs;
194	  }
195	  if (backoff.factor !== undefined) {
196	    if (typeof backoff.factor !== 'number' || !Number.isFinite(backoff.factor) || backoff.factor <= 1) {
197	      throw new Error(
198	        `[fabricator] engine "${designId}": retry.backoff.factor must be a finite number greater than 1; received ${String(backoff.factor)}`,
199	      );
200	    }
201	    resolved.factor = backoff.factor;
202	  }
203	  if (resolved.maxMs < resolved.initialMs) {
204	    throw new Error(
205	      `[fabricator] engine "${designId}": retry.backoff.maxMs (${resolved.maxMs}) must be >= initialMs (${resolved.initialMs})`,
206	    );
207	  }
208	  return { maxAttempts: raw.maxAttempts, backoff: resolved };
209	}
210	
211	/**
212	 * Resolve an engine design's effective retry config. Returns a shape
213	 * with all back-off fields populated. For designs without `retry`,
214	 * returns the zero-attempts shape — signalling fail-fast to the Spider.
215	 */
216	export function resolveEngineRetryConfig(
217	  design: EngineDesign,
218	): { maxAttempts: number; backoff: EngineRetryBackoffConfig } {
219	  if (!design.retry) {
220	    return { maxAttempts: 0, backoff: { ...DEFAULT_ENGINE_RETRY_BACKOFF } };
221	  }
222	  return validateEngineRetryConfig(design.id, design.retry);
223	}
224	
225	/**
226	 * Resolve an engine design's effective retry config, layering an optional
227	 * deployment-level override on top. Pure — Fabricator does not read guild
228	 * config; the caller (Spider) is responsible for handing in the override
229	 * map fetched from `g.guildConfig().spider?.engineRetryOverrides`.
230	 *
231	 * Three-layer overlay (highest wins):
232	 *
233	 *     override > design.retry > built-in defaults
234	 *
235	 * The override is treated as "fields the operator chose to change":
236	 *  - If `override.maxAttempts` is set, it replaces the design's value.
237	 *  - Each `override.backoff.<field>` independently replaces the
238	 *    corresponding design backoff field.
239	 *  - Unspecified fields fall through to `design.retry`, then to
240	 *    `DEFAULT_ENGINE_RETRY_BACKOFF` for backoff sub-fields.
241	 *
242	 * When the design declares no `retry`, the design layer is `{ maxAttempts: 0,
243	 * backoff: DEFAULT }` — so an override that specifies only `maxAttempts: N`
244	 * enables retry on a previously fail-fast design with the default backoff.
245	 *
246	 * The override is assumed already-validated (Spider runs the validation
