1	/**
2	 * Writ-type configuration shape and structural validator.
3	 *
4	 * A `WritTypeConfig` describes a single writ type's state machine and
5	 * lifecycle behaviour: its named states, the permitted transitions between
6	 * them, and the aggregate "all children succeeded" / "any child failed"
7	 * triggers that lift terminal-child outcomes back to the parent. This module
8	 * declares the public TypeScript shape of that config and a pure structural
9	 * validator, `validateWritTypeConfig`.
10	 *
11	 * This module is the foundation of the broader writ-generalization refactor:
12	 * every plugin-registered writ type will pass through the validator before
13	 * becoming usable, and every downstream consumer (Clerk refactor,
14	 * children-behavior engine) imports these types. It is deliberately scoped
15	 * narrowly — no guild-config augmentation, no registration API, no
16	 * consumer-side side-effects.
17	 *
18	 * The validator throws a plain `Error` on the *first* structural violation.
19	 * No typed error class, no accumulated-error mode, no normalization: the
20	 * function is pure validation and returns `void` on success. Error messages
21	 * follow the in-tree animator precedent
22	 * (`[clerk] writTypeConfig.<path>: <problem>; received <value>`).
23	 */
24	
25	// ── Vocabularies ─────────────────────────────────────────────────────
26	
27	/**
28	 * A state's role in the writ-type lifecycle.
29	 *
30	 *   - `'initial'` — the state a newly-created writ starts in. Exactly one
31	 *     state per type must carry this classification.
32	 *   - `'active'`  — a non-terminal, non-initial state. Writs may enter and
33	 *     leave `active` states freely via declared transitions.
34	 *   - `'terminal'` — an absorbing state. Terminal states must not declare
35	 *     any outbound transitions.
36	 */
37	export type WritTypeStateClassification = 'initial' | 'active' | 'terminal';
38	
39	/**
40	 * Known per-state attribute values. Attrs tag states with semantic meaning
41	 * that downstream consumers key on (e.g. the `success` attr identifies the
42	 * state a `childrenBehavior.allSuccess` trigger transitions the parent to
43	 * when the attr is implicitly resolved).
44	 *
45	 * The set below is the v0 vocabulary. For forward-compatibility the attrs
46	 * array accepts any string — consumers should treat unknown attrs as opaque
47	 * tags without special meaning. The named union is exported so editor
48	 * autocomplete surfaces the known values.
49	 */
50	export type KnownWritTypeStateAttr =
51	  | 'success'
52	  | 'failure'
53	  | 'cancelled'
54	  | 'stuck';
55	
56	/**
57	 * The attrs vocabulary as surfaced on a state definition.
58	 *
59	 * Any `KnownWritTypeStateAttr` plus an open `string` escape hatch. Known
60	 * values autocomplete; unknown strings are accepted so plugin-contributed
61	 * writ types can declare new attrs without requiring a coordinated release.
62	 *
63	 * The `& {}` trick preserves the union in editor tooling while still
64	 * widening to `string` at the type-checker level.
65	 */
66	export type WritTypeStateAttr = KnownWritTypeStateAttr | (string & {});
67	
68	// ── Shapes ───────────────────────────────────────────────────────────
69	
70	/**
71	 * An action executed when a `childrenBehavior` trigger fires.
72	 *
73	 * `transition` is the required target state the writ-being-acted-on (the
74	 * parent for upward triggers, each non-terminal child for the downward
75	 * `parentTerminal` trigger) should be moved to when the trigger fires.
76	 *
77	 * The action provides two mutually-exclusive resolution carriers:
78	 *
79	 *   - `copyResolution: true` — copy the triggering child's resolution
80	 *     string onto the parent as part of the transition. Used by upward
81	 *     triggers (`allSuccess` / `anyFailure`) to lift the child's outcome
82	 *     verbatim.
83	 *   - `resolution: string` — a static resolution string written onto each
84	 *     transitioned writ. Used by the downward `parentTerminal` trigger to
85	 *     stamp every cancelled child with the same canonical reason
86	 *     (semantically: "this writ was cancelled because its parent
87	 *     terminated, not on its own merits").
88	 *
89	 * Declaring both `copyResolution: true` and `resolution` on the same action
90	 * is rejected by the validator — the two carriers describe different
91	 * provenance and a single action cannot mean both at once.
92	 *
93	 * Empty action objects and actions without a `transition` field are
94	 * structurally invalid.
95	 */
96	export interface WritTypeChildrenBehaviorAction {
97	  /** State the writ transitions to when the trigger fires. */
98	  transition: string;
99	  /**
100	   * When true, the consumer copies the triggering child's resolution string
101	   * onto the parent as part of the transition. Defaults to unset. Mutually
102	   * exclusive with `resolution`.
103	   */
104	  copyResolution?: boolean;
105	  /**
106	   * Static resolution string written onto each transitioned writ.
107	   * Mutually exclusive with `copyResolution`. Used by the downward
108	   * `parentTerminal` trigger to stamp every cancelled child with the same
109	   * canonical reason.
110	   */
111	  resolution?: string;
112	}
113	
114	/**
115	 * Aggregate-children behaviour for a writ type.
116	 *
117	 * The trigger set covers both cascade directions:
118	 *
119	 *   - `allSuccess` (upward) — fires when *every* child has reached a
120	 *     terminal state and *all* of them carry the `success` attr. The
121	 *     parent is driven to the configured target.
122	 *   - `anyFailure` (upward) — fires when *any* child reaches a terminal
123	 *     state that carries the `failure` attr. The parent is driven to the
124	 *     configured target.
125	 *   - `parentTerminal` (downward) — fires when a writ of *this* type
126	 *     transitions into a terminal state carrying either the `failure` or
127	 *     `cancelled` attr. Every non-terminal descendant is driven to the
128	 *     configured target with the configured resolution. (Recursion to
129	 *     grandchildren happens via natural CDC re-fire on each child's
130	 *     transition, not by in-handler walks.)
131	 *
132	 * All fields are optional. A config that declares no trigger is well-formed
133	 * (no children-driven cascade). Adding a future trigger is a pure additive
134	 * change.
135	 *
136	 * Heterogeneous-children convention: when `parentTerminal` is declared,
137	 * every potential child type must reach the configured `transition` target
138	 * from every non-terminal state via `allowedTransitions`. The validator
139	 * does *not* enforce this cross-type reachability — it cannot, because the
140	 * downward trigger's target lives in child types — so the convention is
141	 * documented and enforced by runtime fail-loud at the `api.transition` call
142	 * site.
143	 */
144	export interface WritTypeChildrenBehavior {
145	  /** Fires when every child terminated successfully. */
146	  allSuccess?: WritTypeChildrenBehaviorAction;
147	  /** Fires when any child terminated in failure. */
148	  anyFailure?: WritTypeChildrenBehaviorAction;
149	  /**
150	   * Fires when a writ of this type transitions into a `failure`- or
151	   * `cancelled`-attr terminal state. Every non-terminal descendant is
152	   * driven to the configured target. The action's `transition` field names
153	   * the target state in the *child* type (typically `cancelled`); the
154	   * validator does not enforce reachability of that name in this config
155	   * because the trigger's downstream target lives in child types.
156	   */
157	  parentTerminal?: WritTypeChildrenBehaviorAction;
158	}
159	
160	/**
161	 * A single state in the writ-type's lifecycle machine.
162	 *
163	 * Each state carries its own name, classification, optional attribute tags,
164	 * and its outbound transition list. Outbound edges are placed per-state so
165	 * the shape is self-contained — a state definition fully describes every
166	 * edge that leaves it.
167	 */
168	export interface WritTypeStateDefinition {
169	  /** Unique (within this config) non-empty state name. */
170	  name: string;
171	  /** The state's role in the lifecycle. */
172	  classification: WritTypeStateClassification;
173	  /**
174	   * Optional semantic tags on this state. Known values autocomplete via
175	   * `KnownWritTypeStateAttr`; unknown strings are accepted so plugin-
176	   * contributed types can declare attrs without a coordinated release.
177	   */
178	  attrs?: WritTypeStateAttr[];
179	  /**
180	   * State names this state may transition to directly. Terminal states
181	   * must declare no outbound transitions; non-terminal states must declare
182	   * at least one reachable path to each configured `childrenBehavior`
183	   * target.
184	   */
185	  allowedTransitions: string[];
186	}
187	
188	/**
189	 * A writ type's complete structural configuration.
190	 *
191	 * Every plugin-registered writ type is described by a single
192	 * `WritTypeConfig`. The config names the type, enumerates its states (with
193	 * per-state outbound edges and classifications), and optionally declares
194	 * aggregate children-driven behaviour.
195	 */
196	export interface WritTypeConfig {
197	  /** The writ type name. Non-empty. Format rules are enforced elsewhere. */
198	  name: string;
199	  /** The lifecycle states for this writ type. */
200	  states: WritTypeStateDefinition[];
201	  /** Optional aggregate-children-triggered behaviour. */
202	  childrenBehavior?: WritTypeChildrenBehavior;
203	}
204	
205	// ── Validator ────────────────────────────────────────────────────────
206	
207	/**
208	 * Valid classification values, used by both the classification check and
209	 * the reachability partition.
210	 */
211	const VALID_CLASSIFICATIONS: readonly WritTypeStateClassification[] = [
212	  'initial',
213	  'active',
214	  'terminal',
215	];
216	
217	/**
218	 * Format a received value for an error message. Mirrors the animator
219	 * precedent's `String(value)` pattern but disambiguates `null`/`undefined`
220	 * so the path-based messages stay informative for the validator's callers.
221	 */
222	function formatReceived(value: unknown): string {
223	  if (value === null) return 'null';
224	  if (value === undefined) return 'undefined';
225	  if (typeof value === 'string') return JSON.stringify(value);
226	  if (typeof value === 'object') {
227	    try {
228	      return JSON.stringify(value);
229	    } catch {
230	      return Object.prototype.toString.call(value);
231	    }
232	  }
233	  return String(value);
234	}
235	
236	/**
237	 * Throw a validator error with the canonical `[clerk] writTypeConfig.<path>:
238	 * <problem>; received <value>` shape.
239	 */
240	function fail(path: string, problem: string, received: unknown): never {
241	  throw new Error(
242	    `[clerk] writTypeConfig.${path}: ${problem}; received ${formatReceived(received)}`,
243	  );
244	}
245	
246	/**
247	 * Validate a `WritTypeConfig` for structural integrity.
248	 *
249	 * Throws on the *first* structural violation. Returns `void` on success;
250	 * the input is not normalized or rewritten. The checks, applied top-down:
251	 *
252	 *   1. `name` is a non-empty string.
253	 *   2. `states` is a non-empty array.
254	 *   3. Each state has a non-empty `name`, with no duplicates.
255	 *   4. Each state's `classification` is one of the three known values.
256	 *   5. Every `allowedTransitions` entry is a string referencing a state
257	 *      that exists in the same config.
258	 *   6. Exactly one state is classified `initial`.
259	 *   7. Every non-initial state has at least one inbound transition from
260	 *      some other state.
261	 *   8. No terminal state declares any outbound transitions.
262	 *   9. Every `childrenBehavior` trigger carries an action object with a
263	 *      non-empty `transition` string. For the upward triggers
264	 *      (`allSuccess`, `anyFailure`) the target must reference a state
265	 *      that exists in this same config.
266	 *  10. Each upward `childrenBehavior` transition target is reachable from
267	 *      every non-terminal state of the config via `allowedTransitions`.
268	 *      The downward `parentTerminal` trigger is excluded — its target
269	 *      lives in child type configs.
270	 *  11. Each action's optional `resolution` field is a non-empty string,
271	 *      and `copyResolution: true` and `resolution` are mutually exclusive
272	 *      on the same action.
273	 *
274	 * Error messages take the shape `[clerk] writTypeConfig.<path>: <problem>;
275	 * received <value>` — e.g. `states[2].classification`,
276	 * `childrenBehavior.anyFailure.transition`.
277	 */
278	export function validateWritTypeConfig(config: WritTypeConfig): void {
279	  // ── Top-level shape ──────────────────────────────────────────────
280	
281	  if (typeof config !== 'object' || config === null) {
282	    fail('', 'must be an object', config);
283	  }
284	
285	  if (typeof config.name !== 'string' || config.name.length === 0) {
286	    fail('name', 'must be a non-empty string', config.name);
287	  }
288	
289	  if (!Array.isArray(config.states)) {
290	    fail('states', 'must be an array', config.states);
291	  }
292	
293	  if (config.states.length === 0) {
294	    fail('states', 'must contain at least one state', config.states);
295	  }
296	
297	  // ── Per-state shape + name uniqueness ────────────────────────────
298	
299	  const seenNames = new Set<string>();
300	  const stateIndexByName = new Map<string, number>();
301	
302	  for (let i = 0; i < config.states.length; i += 1) {
303	    const state = config.states[i];
304	    const path = `states[${i}]`;
305	
306	    if (typeof state !== 'object' || state === null) {
307	      fail(path, 'must be an object', state);
308	    }
309	
310	    if (typeof state.name !== 'string' || state.name.length === 0) {
311	      fail(`${path}.name`, 'must be a non-empty string', state.name);
312	    }
313	
314	    if (seenNames.has(state.name)) {
315	      fail(`${path}.name`, 'duplicate state name', state.name);
316	    }
317	    seenNames.add(state.name);
318	    stateIndexByName.set(state.name, i);
319	
320	    if (!VALID_CLASSIFICATIONS.includes(state.classification)) {
321	      fail(
322	        `${path}.classification`,
323	        `must be one of ${VALID_CLASSIFICATIONS.join(', ')}`,
324	        state.classification,
325	      );
326	    }
327	
328	    if (state.attrs !== undefined) {
329	      if (!Array.isArray(state.attrs)) {
330	        fail(`${path}.attrs`, 'must be an array when provided', state.attrs);
331	      }
332	      for (let a = 0; a < state.attrs.length; a += 1) {
333	        const attr = state.attrs[a];
334	        if (typeof attr !== 'string' || attr.length === 0) {
335	          fail(`${path}.attrs[${a}]`, 'must be a non-empty string', attr);
336	        }
337	      }
338	    }
339	
340	    if (!Array.isArray(state.allowedTransitions)) {
341	      fail(`${path}.allowedTransitions`, 'must be an array', state.allowedTransitions);
342	    }
343	
344	    for (let t = 0; t < state.allowedTransitions.length; t += 1) {
345	      const target = state.allowedTransitions[t];
346	      if (typeof target !== 'string' || target.length === 0) {
347	        fail(
348	          `${path}.allowedTransitions[${t}]`,
349	          'must be a non-empty string',
350	          target,
351	        );
352	      }
353	    }
354	  }
355	
356	  // ── Transition-target existence ──────────────────────────────────
357	
358	  for (let i = 0; i < config.states.length; i += 1) {
359	    const state = config.states[i];
360	    for (let t = 0; t < state.allowedTransitions.length; t += 1) {
361	      const target = state.allowedTransitions[t];
362	      if (!stateIndexByName.has(target)) {
363	        fail(
364	          `states[${i}].allowedTransitions[${t}]`,
365	          `references unknown state "${target}"`,
366	          target,
367	        );
368	      }
369	    }
370	  }
371	
372	  // ── Exactly one initial state ────────────────────────────────────
373	
374	  const initialIndices: number[] = [];
375	  for (let i = 0; i < config.states.length; i += 1) {
376	    if (config.states[i].classification === 'initial') initialIndices.push(i);
377	  }
378	
379	  if (initialIndices.length === 0) {
380	    fail(
381	      'states',
382	      'must contain exactly one state with classification "initial" (found zero)',
383	      initialIndices.length,
384	    );
385	  }
386	  if (initialIndices.length > 1) {
387	    const names = initialIndices.map((i) => config.states[i].name);
388	    fail(
389	      'states',
390	      `must contain exactly one state with classification "initial" (found ${initialIndices.length}: ${names.join(', ')})`,
391	      initialIndices.length,
392	    );
393	  }
394	
395	  // ── Terminal states declare no outbound transitions ──────────────
396	
397	  for (let i = 0; i < config.states.length; i += 1) {
398	    const state = config.states[i];
399	    if (state.classification === 'terminal' && state.allowedTransitions.length > 0) {
400	      fail(
401	        `states[${i}].allowedTransitions`,
402	        `terminal state "${state.name}" must not declare any outbound transitions`,
403	        state.allowedTransitions,
404	      );
405	    }
406	  }
407	
408	  // ── Inbound-transition coverage for non-initial states ───────────
409	
410	  const inboundCount = new Map<string, number>();
411	  for (const state of config.states) {
412	    for (const target of state.allowedTransitions) {
413	      inboundCount.set(target, (inboundCount.get(target) ?? 0) + 1);
414	    }
415	  }
416	
417	  for (let i = 0; i < config.states.length; i += 1) {
418	    const state = config.states[i];
419	    if (state.classification === 'initial') continue;
420	    if ((inboundCount.get(state.name) ?? 0) === 0) {
421	      fail(
422	        `states[${i}]`,
423	        `non-initial state "${state.name}" must have at least one inbound transition`,
424	        state.name,
425	      );
426	    }
427	  }
428	
429	  // ── childrenBehavior triggers ────────────────────────────────────
430	
431	  const cb = config.childrenBehavior;
432	  if (cb !== undefined) {
433	    if (typeof cb !== 'object' || cb === null) {
434	      fail('childrenBehavior', 'must be an object when provided', cb);
435	    }
436	
437	    // Upward triggers fire on the parent's own state machine — their
438	    // `transition` target must reference a state declared in *this*
439	    // config and is subject to same-config reachability checking.
440	    //
441	    // The downward `parentTerminal` trigger drives non-terminal children
442	    // through *their* own state machines — its `transition` target lives
443	    // in child type configs. This validator is deliberately standalone
444	    // and pure (no cross-type registry awareness), so the downward
445	    // trigger's target is structurally validated (existence as a string,
446	    // non-empty, optional resolution non-empty, mutual exclusion with
447	    // copyResolution) but does *not* participate in the same-config
448	    // existence or reachability checks. Runtime fail-loud at the
449	    // `api.transition` call site enforces the per-child-type contract.
450	    const upwardTriggerNames = ['allSuccess', 'anyFailure'] as const;
451	    const downwardTriggerNames = ['parentTerminal'] as const;
452	    const allTriggerNames = [...upwardTriggerNames, ...downwardTriggerNames] as const;
453	
454	    for (const triggerName of allTriggerNames) {
455	      const action = cb[triggerName];
456	      if (action === undefined) continue;
457	
458	      const actionPath = `childrenBehavior.${triggerName}`;
459	
460	      if (typeof action !== 'object' || action === null) {
461	        fail(actionPath, 'must be an object when provided', action);
462	      }
463	
464	      if (Object.keys(action).length === 0) {
465	        fail(actionPath, 'must not be an empty object', action);
466	      }
467	
468	      if (typeof action.transition !== 'string' || action.transition.length === 0) {
469	        fail(
470	          `${actionPath}.transition`,
471	          'must be a non-empty string',
472	          action.transition,
473	        );
474	      }
475	
476	      if (action.copyResolution !== undefined && typeof action.copyResolution !== 'boolean') {
477	        fail(
478	          `${actionPath}.copyResolution`,
479	          'must be a boolean when provided',
480	          action.copyResolution,
481	        );
482	      }
483	
484	      if (action.resolution !== undefined) {
485	        if (typeof action.resolution !== 'string' || action.resolution.length === 0) {
486	          fail(
487	            `${actionPath}.resolution`,
488	            'must be a non-empty string when provided',
489	            action.resolution,
490	          );
491	        }
492	      }
493	
494	      if (action.copyResolution === true && action.resolution !== undefined) {
495	        fail(
496	          actionPath,
497	          'copyResolution and resolution are mutually exclusive — pick one',
498	          { copyResolution: action.copyResolution, resolution: action.resolution },
499	        );
500	      }
501	    }
502	
503	    // Upward triggers only: target must reference a declared state in
504	    // this same config.
505	    for (const triggerName of upwardTriggerNames) {
506	      const action = cb[triggerName];
507	      if (action === undefined) continue;
508	      if (!stateIndexByName.has(action.transition)) {
509	        fail(
510	          `childrenBehavior.${triggerName}.transition`,
511	          `references unknown state "${action.transition}"`,
512	          action.transition,
513	        );
514	      }
515	    }
516	
517	    // ── Reachability: each upward trigger target must be reachable
518	    // from every non-terminal state via allowedTransitions. The
519	    // downward `parentTerminal` trigger is excluded — its target
520	    // lives in child type configs, not this one, so same-config
521	    // reachability is meaningless for it. ────────────────────────
522	    const nonTerminalStates = config.states.filter(
523	      (s) => s.classification !== 'terminal',
524	    );
525	
526	    // Compute reverse-reachability from each trigger target: BFS over
527	    // the reversed graph starts at the target and yields every state
528	    // from which the target is reachable. This is O(V + E) per target
529	    // — one traversal regardless of how many non-terminal states the
530	    // config declares.
531	    const reverseAdj = new Map<string, string[]>();
532	    for (const state of config.states) {
533	      for (const target of state.allowedTransitions) {
534	        const bucket = reverseAdj.get(target);
535	        if (bucket) {
536	          bucket.push(state.name);
537	        } else {
538	          reverseAdj.set(target, [state.name]);
539	        }
540	      }
541	    }
542	
543	    function reverseReachable(from: string): Set<string> {
544	      const seen = new Set<string>([from]);
545	      const queue: string[] = [from];
546	      while (queue.length > 0) {
547	        const node = queue.shift()!;
548	        const preds = reverseAdj.get(node) ?? [];
549	        for (const pred of preds) {
550	          if (!seen.has(pred)) {
551	            seen.add(pred);
552	            queue.push(pred);
553	          }
554	        }
555	      }
556	      return seen;
557	    }
558	
559	    for (const triggerName of upwardTriggerNames) {
560	      const action = cb[triggerName];
561	      if (action === undefined) continue;
562	      const target = action.transition;
563	      const reachableFrom = reverseReachable(target);
564	      for (const state of nonTerminalStates) {
565	        if (!reachableFrom.has(state.name)) {
566	          fail(
567	            `childrenBehavior.${triggerName}.transition`,
568	            `state "${target}" is not reachable from non-terminal state "${state.name}" via allowedTransitions`,
569	            target,
570	          );
571	        }
572	      }
573	    }
574	  }
575	}
