/**
 * The Laboratory's phase orchestrator engines.
 *
 * The post-and-collect-default rig template enumerates five phases as
 * a backbone (setup → scenario → probes → archive → teardown), one
 * engine per phase. Each phase engine is a clockwork orchestrator: it
 * reads `writ.ext.laboratory.config`, computes the per-phase graft,
 * and returns immediately with `{ status: 'completed', graft, ...}`.
 * The grafted engines do the real work; phase orchestrators are
 * organizational.
 *
 * Phase orchestrators do not isolate data — all grafted engines
 * share a single namespace, so cross-phase upstream refs work
 * naturally. Engine ids follow stable naming conventions
 * (`fixture-<id>-setup`, `scenario`, `probe-<id>`, `archive`,
 * `fixture-<id>-teardown`); each phase derives the ids it needs
 * from the trial config without going through prior phases' yields.
 *
 * Why staged phases instead of one god orchestrator:
 *
 *   - Template documents the trial flow as the user-facing shape
 *     (the template is no longer a one-engine no-op).
 *   - Per-phase failure visibility: oculus shows
 *     `lab.probes-phase` failed, not "the orchestrator failed
 *     somewhere".
 *   - Each phase has cohesive logic (DAG sort, parallel scatter,
 *     reverse-sequential chain) — splitting them avoids one big
 *     function with phase-mode flags.
 *   - Sets up the extension point: a future plugin contributing a
 *     `lab.warmup-phase` slots into a custom template alongside
 *     existing phases without forking a god engine.
 *
 * graftTail is set only on `lab.teardown-phase` (the rig's true end
 * for completion gating). Intermediate phase orchestrators omit
 * graftTail so each next phase fires immediately when the prior
 * orchestrator returns — real work-engines wait via their explicit
 * upstream refs, not graftTail propagation.
 */

import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';
import type { WritDoc } from '@shardworks/clerk-apparatus';
import type { RigTemplateEngine, SpiderEngineRunResult } from '@shardworks/spider-apparatus';
import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';

// ── Shared helpers ─────────────────────────────────────────────────

/**
 * Stable engine-id naming conventions. Every phase derives the ids
 * it needs from the trial config using these helpers — no
 * cross-phase data flow is required for naming.
 */
export const SETUP_ID = (fixtureId: string): string => `fixture-${fixtureId}-setup`;
export const TEARDOWN_ID = (fixtureId: string): string => `fixture-${fixtureId}-teardown`;
export const SCENARIO_ID = 'scenario';
export const PROBE_ID = (probeId: string): string => `probe-${probeId}`;
export const ARCHIVE_ID = 'archive';

/**
 * Convention: derive a fixture's teardown engine id from its setup
 * engine id when no explicit override is provided. Replaces a
 * trailing `-setup` with `-teardown`. If the setup id does not end
 * in `-setup`, appends `-teardown`.
 */
export function deriveTeardownEngineId(fixture: TrialFixtureDecl): string {
  if (fixture.teardownEngineId !== undefined) return fixture.teardownEngineId;
  if (fixture.engineId.endsWith('-setup')) {
    return fixture.engineId.replace(/-setup$/, '-teardown');
  }
  return `${fixture.engineId}-teardown`;
}

/**
 * Topologically sort fixtures by dependsOn. Every fixture appears
 * after all of its dependencies. Stable: among fixtures whose
 * dependencies are all already placed, declaration order is
 * preserved.
 *
 * Throws on cycles, unknown dependsOn references, or duplicate ids.
 */
export function topoSortFixtures(fixtures: TrialFixtureDecl[]): TrialFixtureDecl[] {
  const byId = new Map<string, TrialFixtureDecl>();
  for (const fixture of fixtures) {
    if (byId.has(fixture.id)) {
      throw new Error(`[lab] duplicate fixture id: "${fixture.id}"`);
    }
    byId.set(fixture.id, fixture);
  }

  for (const fixture of fixtures) {
    for (const dep of fixture.dependsOn ?? []) {
      if (!byId.has(dep)) {
        throw new Error(
          `[lab] fixture "${fixture.id}" dependsOn unknown fixture "${dep}"`,
        );
      }
    }
  }

  const result: TrialFixtureDecl[] = [];
  const placed = new Set<string>();
  const remaining = [...fixtures];

  while (remaining.length > 0) {
    const before = remaining.length;
    for (let i = 0; i < remaining.length; i += 1) {
      const fixture = remaining[i]!;
      const deps = fixture.dependsOn ?? [];
      if (deps.every((d) => placed.has(d))) {
        result.push(fixture);
        placed.add(fixture.id);
        remaining.splice(i, 1);
        i -= 1;
      }
    }
    if (remaining.length === before) {
      const ids = remaining.map((f) => f.id).join(', ');
      throw new Error(`[lab] fixture dependsOn cycle among: ${ids}`);
    }
  }

  return result;
}

/**
 * Read and validate the trial config from a writ. All phase
 * orchestrators share this entry path — fail-loud on missing
 * config so the manifest CLI's validation contract is the only
 * gate.
 */
function readTrialConfig(givens: Record<string, unknown>, phaseEngineId: string): {
  writ: WritDoc;
  config: LaboratoryTrialConfig;
} {
  const writ = givens.writ as WritDoc | undefined;
  if (!writ) {
    throw new Error(
      `[${phaseEngineId}] missing required given "writ" — the rig template must pass \${writ}.`,
    );
  }
  const config = (writ.ext as { laboratory?: { config?: LaboratoryTrialConfig } } | undefined)
    ?.laboratory?.config;
  if (!config) {
    throw new Error(
      `[${phaseEngineId}] trial writ ${writ.id} missing ext.laboratory.config — manifest CLI should reject this at post time.`,
    );
  }
  return { writ, config };
}

// ── Per-phase graft builders (pure; tested directly) ───────────────

/**
 * Build the setup phase's graft: one engine per fixture, in topo
 * order. A fixture's setup engine upstreams its dependsOn fixtures'
 * setup engines (or the head — `headEngineId` — when it has no
 * deps).
 */
export function buildSetupGraft(
  config: LaboratoryTrialConfig,
  headEngineId: string,
): { graft: RigTemplateEngine[]; ordered: TrialFixtureDecl[] } {
  const ordered = topoSortFixtures(config.fixtures);
  const graft: RigTemplateEngine[] = [];
  for (const fixture of ordered) {
    const deps = fixture.dependsOn ?? [];
    const upstream = deps.length > 0 ? deps.map(SETUP_ID) : [headEngineId];
    graft.push({
      id: SETUP_ID(fixture.id),
      designId: fixture.engineId,
      upstream,
      givens: fixture.givens,
    });
  }
  return { graft, ordered };
}

/**
 * Build the scenario phase's graft: one engine for the scenario.
 * Upstreams every fixture's setup engine, so it waits for the full
 * setup wave to complete. When there are no fixtures, upstreams
 * the head (the scenario phase orchestrator's own id).
 */
export function buildScenarioGraft(
  config: LaboratoryTrialConfig,
  headEngineId: string,
): RigTemplateEngine[] {
  const upstream =
    config.fixtures.length > 0
      ? topoSortFixtures(config.fixtures).map((f) => SETUP_ID(f.id))
      : [headEngineId];
  return [
    {
      id: SCENARIO_ID,
      designId: config.scenario.engineId,
      upstream,
      givens: config.scenario.givens,
    },
  ];
}

/**
 * Build the probes phase's graft: one engine per probe. Each probe
 * upstreams the scenario engine; probes themselves run in parallel.
 */
export function buildProbesGraft(
  config: LaboratoryTrialConfig,
): RigTemplateEngine[] {
  return config.probes.map((probe) => ({
    id: PROBE_ID(probe.id),
    designId: probe.engineId,
    upstream: [SCENARIO_ID],
    givens: probe.givens,
  }));
}

/**
 * Build the archive phase's graft: one archive engine. Upstreams
 * every probe engine; or the scenario engine when there are no
 * probes.
 */
export function buildArchiveGraft(
  config: LaboratoryTrialConfig,
): RigTemplateEngine[] {
  const upstream =
    config.probes.length > 0
      ? config.probes.map((p) => PROBE_ID(p.id))
      : [SCENARIO_ID];
  return [
    {
      id: ARCHIVE_ID,
      designId: config.archive.engineId,
      upstream,
      givens: config.archive.givens,
    },
  ];
}

/**
 * Build the teardown phase's graft: one engine per fixture, REVERSE
 * topo order, sequential chain rooted at archive. Sequential (not
 * parallel) so a teardown failure stops the chain rather than
 * shredding sibling teardowns concurrently.
 *
 * Returns the graft and the tail engine id (the rig's true end —
 * teardown phase sets graftTail to this for completion gating).
 */
export function buildTeardownGraft(
  config: LaboratoryTrialConfig,
): { graft: RigTemplateEngine[]; tail: string } {
  const ordered = topoSortFixtures(config.fixtures);
  const graft: RigTemplateEngine[] = [];
  let prevTail: string = ARCHIVE_ID;
  for (let i = ordered.length - 1; i >= 0; i -= 1) {
    const fixture = ordered[i]!;
    const id = TEARDOWN_ID(fixture.id);
    graft.push({
      id,
      designId: deriveTeardownEngineId(fixture),
      upstream: [prevTail],
      givens: fixture.givens,
    });
    prevTail = id;
  }
  return { graft, tail: prevTail };
}

// ── Phase orchestrator engines ─────────────────────────────────────

const setupPhaseEngine: EngineDesign = {
  id: 'lab.setup-phase',
  async run(givens, context): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.setup-phase');
    const { graft, ordered } = buildSetupGraft(config, context.engineId);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: {
        fixtureCount: ordered.length,
        fixtureIds: ordered.map((f) => f.id),
      },
      graft,
      // graftTail intentionally unset: the scenario engine has
      //   explicit upstream refs into each fixture-setup, so the
      //   scenario phase can fire immediately upon this engine's
      //   return without waiting for fixtures to complete first.
    };
    return result as EngineRunResult;
  },
};

const scenarioPhaseEngine: EngineDesign = {
  id: 'lab.scenario-phase',
  async run(givens, context): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.scenario-phase');
    const graft = buildScenarioGraft(config, context.engineId);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { scenarioEngine: config.scenario.engineId },
      graft,
    };
    return result as EngineRunResult;
  },
};

const probesPhaseEngine: EngineDesign = {
  id: 'lab.probes-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.probes-phase');
    const graft = buildProbesGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: {
        probeCount: config.probes.length,
        probeIds: config.probes.map((p) => p.id),
      },
      graft,
    };
    return result as EngineRunResult;
  },
};

const archivePhaseEngine: EngineDesign = {
  id: 'lab.archive-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.archive-phase');
    const graft = buildArchiveGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { archiveEngine: config.archive.engineId },
      graft,
    };
    return result as EngineRunResult;
  },
};

const teardownPhaseEngine: EngineDesign = {
  id: 'lab.teardown-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.teardown-phase');
    const { graft, tail } = buildTeardownGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { teardownCount: config.fixtures.length },
      graft,
      // graftTail set: this is the rig's true end. Spider waits
      //   for `tail` to complete before considering the rig done.
      //   When there are no fixtures, tail equals ARCHIVE_ID — the
      //   archive engine is the last real work in that case.
      graftTail: tail,
    };
    return result as EngineRunResult;
  },
};

export const phaseEngines = {
  'lab.setup-phase': setupPhaseEngine,
  'lab.scenario-phase': scenarioPhaseEngine,
  'lab.probes-phase': probesPhaseEngine,
  'lab.archive-phase': archivePhaseEngine,
  'lab.teardown-phase': teardownPhaseEngine,
} as const;

toolUseResult.content:
/**
 * Tests for the per-phase graft builders and the topo sort helper.
 *
 * The graft builders are pure functions — given a trial config (and
 * the head engine id for setup/scenario), each returns the
 * RigTemplateEngine[] its phase contributes to the rig. Together the
 * five graft builders produce a flat engine list equivalent to what
 * the previous one-engine orchestrator produced; they're tested
 * piece-wise here.
 */

import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import {
  buildArchiveGraft,
  buildProbesGraft,
  buildScenarioGraft,
  buildSetupGraft,
  buildTeardownGraft,
  topoSortFixtures,
} from './phases.ts';
import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';

const HEAD = 'phase-head';

function trialConfig(over: Partial<LaboratoryTrialConfig> = {}): LaboratoryTrialConfig {
  return {
    slug: 'test',
    fixtures: [],
    scenario: { engineId: 'lab.commission-post-xguild', givens: {} },
    probes: [],
    archive: { engineId: 'lab.archive', givens: {} },
    ...over,
  };
}

function fixture(id: string, over: Partial<TrialFixtureDecl> = {}): TrialFixtureDecl {
  return {
    id,
    engineId: `lab.${id}-setup`,
    givens: {},
    ...over,
  };
}

// ── topoSortFixtures ────────────────────────────────────────────────

describe('topoSortFixtures', () => {
  it('preserves declaration order when there are no deps', () => {
    const fixtures = [fixture('a'), fixture('b'), fixture('c')];
    const sorted = topoSortFixtures(fixtures);
    assert.deepEqual(
      sorted.map((f) => f.id),
      ['a', 'b', 'c'],
    );
  });

  it('places dependencies before dependents', () => {
    const fixtures = [
      fixture('child', { dependsOn: ['parent'] }),
      fixture('parent'),
    ];
    const sorted = topoSortFixtures(fixtures);
    assert.deepEqual(
      sorted.map((f) => f.id),
      ['parent', 'child'],
    );
  });

  it('handles a deep chain', () => {
    const fixtures = [
      fixture('d', { dependsOn: ['c'] }),
      fixture('c', { dependsOn: ['b'] }),
      fixture('b', { dependsOn: ['a'] }),
      fixture('a'),
    ];
    const sorted = topoSortFixtures(fixtures);
    assert.deepEqual(
      sorted.map((f) => f.id),
      ['a', 'b', 'c', 'd'],
    );
  });

  it('handles diamond dependencies', () => {
    const fixtures = [
      fixture('top'),
      fixture('left', { dependsOn: ['top'] }),
      fixture('right', { dependsOn: ['top'] }),
      fixture('bottom', { dependsOn: ['left', 'right'] }),
    ];
    const sorted = topoSortFixtures(fixtures);
    const positionOf = (id: string) => sorted.findIndex((f) => f.id === id);
    assert.ok(positionOf('top') < positionOf('left'));
    assert.ok(positionOf('top') < positionOf('right'));
    assert.ok(positionOf('left') < positionOf('bottom'));
    assert.ok(positionOf('right') < positionOf('bottom'));
  });

  it('throws on a cycle', () => {
    const fixtures = [
      fixture('a', { dependsOn: ['b'] }),
      fixture('b', { dependsOn: ['a'] }),
    ];
    assert.throws(() => topoSortFixtures(fixtures), /cycle/i);
  });

  it('throws on unknown dependsOn reference', () => {
    const fixtures = [fixture('a', { dependsOn: ['ghost'] })];
    assert.throws(() => topoSortFixtures(fixtures), /unknown fixture "ghost"/);
  });

  it('throws on duplicate fixture ids', () => {
    const fixtures = [fixture('a'), fixture('a')];
    assert.throws(() => topoSortFixtures(fixtures), /duplicate fixture id/);
  });
});

// ── buildSetupGraft ────────────────────────────────────────────────

describe('buildSetupGraft', () => {
  it('produces empty graft for no fixtures', () => {
    const { graft, ordered } = buildSetupGraft(trialConfig(), HEAD);
    assert.deepEqual(graft, []);
    assert.deepEqual(ordered, []);
  });

  it('first wave of fixture-setups upstreams the head engine', () => {
    const { graft } = buildSetupGraft(
      trialConfig({ fixtures: [fixture('codex'), fixture('test-guild')] }),
      HEAD,
    );
    const codexSetup = graft.find((e) => e.id === 'fixture-codex-setup')!;
    const guildSetup = graft.find((e) => e.id === 'fixture-test-guild-setup')!;
    assert.deepEqual(codexSetup.upstream, [HEAD]);
    assert.deepEqual(guildSetup.upstream, [HEAD]);
  });

  it('dependent fixture upstreams its dependency', () => {
    const { graft } = buildSetupGraft(
      trialConfig({
        fixtures: [
          fixture('codex'),
          fixture('test-guild', { dependsOn: ['codex'] }),
        ],
      }),
      HEAD,
    );
    const guildSetup = graft.find((e) => e.id === 'fixture-test-guild-setup')!;
    assert.deepEqual(guildSetup.upstream, ['fixture-codex-setup']);
  });

  it('returns ordered fixtures matching topo sort', () => {
    const { ordered } = buildSetupGraft(
      trialConfig({
        fixtures: [
          fixture('child', { dependsOn: ['parent'] }),
          fixture('parent'),
        ],
      }),
      HEAD,
    );
    assert.deepEqual(ordered.map((f) => f.id), ['parent', 'child']);
  });

  it('passes fixture givens to the setup engine', () => {
    const givens = { name: 'codex', remoteUrl: 'git@github.com:foo/bar' };
    const { graft } = buildSetupGraft(
      trialConfig({ fixtures: [fixture('codex', { givens })] }),
      HEAD,
    );
    const setup = graft.find((e) => e.id === 'fixture-codex-setup')!;
    assert.deepEqual(setup.givens, givens);
  });
});

// ── buildScenarioGraft ─────────────────────────────────────────────

describe('buildScenarioGraft', () => {
  it('upstreams the head engine when no fixtures', () => {
    const graft = buildScenarioGraft(trialConfig(), HEAD);
    assert.equal(graft.length, 1);
    assert.equal(graft[0]!.id, 'scenario');
    assert.deepEqual(graft[0]!.upstream, [HEAD]);
  });

  it('upstreams every fixture-setup', () => {
    const graft = buildScenarioGraft(
      trialConfig({ fixtures: [fixture('codex'), fixture('test-guild')] }),
      HEAD,
    );
    assert.deepEqual(
      [...graft[0]!.upstream!].sort(),
      ['fixture-codex-setup', 'fixture-test-guild-setup'].sort(),
    );
  });

  it('passes scenario givens through unchanged', () => {
    const graft = buildScenarioGraft(
      trialConfig({
        scenario: {
          engineId: 'lab.commission-post-xguild',
          givens: { briefPath: 'files/brief.md' },
        },
      }),
      HEAD,
    );
    assert.deepEqual(graft[0]!.givens, { briefPath: 'files/brief.md' });
  });

  it('uses the scenario engine id from config', () => {
    const graft = buildScenarioGraft(
      trialConfig({
        scenario: { engineId: 'custom.scenario', givens: {} },
      }),
      HEAD,
    );
    assert.equal(graft[0]!.designId, 'custom.scenario');
  });
});

// ── buildProbesGraft ───────────────────────────────────────────────

describe('buildProbesGraft', () => {
  it('produces empty graft for no probes', () => {
    const graft = buildProbesGraft(trialConfig());
    assert.deepEqual(graft, []);
  });

  it('every probe upstreams scenario; probes run parallel to each other', () => {
    const graft = buildProbesGraft(
      trialConfig({
        probes: [
          { id: 'stacks', engineId: 'lab.probe-stacks-dump', givens: {} },
          { id: 'git', engineId: 'lab.probe-git-range', givens: {} },
        ],
      }),
    );
    const stacks = graft.find((e) => e.id === 'probe-stacks')!;
    const git = graft.find((e) => e.id === 'probe-git')!;
    assert.deepEqual(stacks.upstream, ['scenario']);
    assert.deepEqual(git.upstream, ['scenario']);
  });

  it('passes probe givens through unchanged', () => {
    const graft = buildProbesGraft(
      trialConfig({
        probes: [
          {
            id: 'stacks',
            engineId: 'lab.probe-stacks-dump',
            givens: { outputPath: 'stacks-export/' },
          },
        ],
      }),
    );
    assert.deepEqual(graft[0]!.givens, { outputPath: 'stacks-export/' });
  });
});

// ── buildArchiveGraft ──────────────────────────────────────────────

describe('buildArchiveGraft', () => {
  it('upstreams scenario when no probes', () => {
    const graft = buildArchiveGraft(trialConfig());
    assert.equal(graft.length, 1);
    assert.equal(graft[0]!.id, 'archive');
    assert.deepEqual(graft[0]!.upstream, ['scenario']);
  });

  it('upstreams every probe when probes exist', () => {
    const graft = buildArchiveGraft(
      trialConfig({
        probes: [
          { id: 'stacks', engineId: 'lab.probe-stacks-dump', givens: {} },
          { id: 'git', engineId: 'lab.probe-git-range', givens: {} },
        ],
      }),
    );
    assert.deepEqual(
      [...graft[0]!.upstream!].sort(),
      ['probe-git', 'probe-stacks'],
    );
  });

  it('passes archive givens through unchanged', () => {
    const graft = buildArchiveGraft(
      trialConfig({
        archive: { engineId: 'lab.archive', givens: { target: 'sanctum' } },
      }),
    );
    assert.deepEqual(graft[0]!.givens, { target: 'sanctum' });
  });
});

// ── buildTeardownGraft ─────────────────────────────────────────────

describe('buildTeardownGraft', () => {
  it('returns archive as tail when there are no fixtures', () => {
    const { graft, tail } = buildTeardownGraft(trialConfig());
    assert.deepEqual(graft, []);
    assert.equal(tail, 'archive');
  });

  it('teardowns run in reverse topo order, sequential chain rooted at archive', () => {
    const { graft, tail } = buildTeardownGraft(
      trialConfig({
        fixtures: [
          fixture('codex'),
          fixture('test-guild', { dependsOn: ['codex'] }),
        ],
      }),
    );
    const guildTeardown = graft.find((e) => e.id === 'fixture-test-guild-teardown')!;
    const codexTeardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
    assert.deepEqual(guildTeardown.upstream, ['archive']);
    assert.deepEqual(codexTeardown.upstream, ['fixture-test-guild-teardown']);
    assert.equal(tail, 'fixture-codex-teardown');
  });

  it('derives teardown engine id by replacing -setup with -teardown', () => {
    const { graft } = buildTeardownGraft(
      trialConfig({ fixtures: [fixture('codex')] }),
    );
    const teardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
    assert.equal(teardown.designId, 'lab.codex-teardown');
  });

  it('falls back to "<engineId>-teardown" when setup id does not end in -setup', () => {
    const { graft } = buildTeardownGraft(
      trialConfig({
        fixtures: [fixture('weird', { engineId: 'lab.bootstrap' })],
      }),
    );
    const teardown = graft.find((e) => e.id === 'fixture-weird-teardown')!;
    assert.equal(teardown.designId, 'lab.bootstrap-teardown');
  });

  it('honors an explicit teardownEngineId override', () => {
    const { graft } = buildTeardownGraft(
      trialConfig({
        fixtures: [
          fixture('codex', {
            engineId: 'lab.custom-setup',
            teardownEngineId: 'lab.completely-different',
          }),
        ],
      }),
    );
    const teardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
    assert.equal(teardown.designId, 'lab.completely-different');
  });

  it('passes fixture givens to teardown engines (same as setup)', () => {
    const givens = { name: 'codex', remoteUrl: 'git@github.com:foo/bar' };
    const { graft } = buildTeardownGraft(
      trialConfig({ fixtures: [fixture('codex', { givens })] }),
    );
    const teardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
    assert.deepEqual(teardown.givens, givens);
  });
});

// ── End-to-end shape — five phases yield the same flat graph ───────

describe('staged-phase composition matches the unified flat graph', () => {
  it('two-fixture trial composes setup → scenario → probes → archive → teardown correctly', () => {
    const config = trialConfig({
      fixtures: [
        fixture('codex'),
        fixture('test-guild', { dependsOn: ['codex'] }),
      ],
      probes: [
        { id: 'stacks', engineId: 'lab.probe-stacks-dump', givens: {} },
      ],
    });

    // What each phase orchestrator would graft:
    const { graft: setupGraft } = buildSetupGraft(config, 'lab.setup-phase');
    const scenarioGraft = buildScenarioGraft(config, 'lab.scenario-phase');
    const probesGraft = buildProbesGraft(config);
    const archiveGraft = buildArchiveGraft(config);
    const { graft: teardownGraft, tail } = buildTeardownGraft(config);

    // Combined runtime engine list (ignoring the orchestrators
    // themselves; those live in the static template).
    const allWorkEngines = [
      ...setupGraft,
      ...scenarioGraft,
      ...probesGraft,
      ...archiveGraft,
      ...teardownGraft,
    ];

    const ids = allWorkEngines.map((e) => e.id);
    assert.deepEqual(ids, [
      'fixture-codex-setup',
      'fixture-test-guild-setup',
      'scenario',
      'probe-stacks',
      'archive',
      'fixture-test-guild-teardown',
      'fixture-codex-teardown',
    ]);

    // Cross-phase wiring: scenario waits on both fixture-setups,
    // probe waits on scenario, archive waits on probe, teardowns
    // chain back from archive in reverse topo.
    const scenario = allWorkEngines.find((e) => e.id === 'scenario')!;
    const probe = allWorkEngines.find((e) => e.id === 'probe-stacks')!;
    const archive = allWorkEngines.find((e) => e.id === 'archive')!;
    assert.deepEqual(
      [...scenario.upstream!].sort(),
      ['fixture-codex-setup', 'fixture-test-guild-setup'],
    );
    assert.deepEqual(probe.upstream, ['scenario']);
    assert.deepEqual(archive.upstream, ['probe-stacks']);
    assert.equal(tail, 'fixture-codex-teardown');
  });
});

