    const ids = allWorkEngines.map((e) => e.id);
    assert.deepEqual(ids, [
      'fixture-codex-setup',
      'fixture-test-guild-setup',
      'scenario',
      'probe-stacks',
      'archive',
      'fixture-test-guild-teardown',
      'fixture-codex-teardown',
